   i &amp; 1  \cr 

 } } \right)\left( {\matrix{
   1 &amp; 0  \cr 
   i &amp; 1  \cr 

 } } \right) = \left( {\matrix{
   1 &amp; 0  \cr 
   {2i} &amp; 1  \cr 

 } } \right)$$<br><br>$${B^3} = \left( {\matrix{
   1 &amp; 0  \cr 
   {2i} &amp; 1  \cr 

 } } \right)\left( {\matrix{
   1 &amp; 0  \cr 
   i &amp; 1  \cr 

 } } \right) \Rightarrow {B^3} = \left( {\matrix{
   1 &amp; 0  \cr 
   {3i} &amp; 1  \cr 

 } } \right)$$<br><br>Similarly $${B^{2021}} = \left( {\matrix{
   1 &amp; 0  \cr 
   {2021i} &amp; 1  \cr 

 } } \right)$$<br><br>$$\therefore$$ $$A{Q^{2021}} = {A^T} = A{A^T}{B^{2021}}\,A{A^T} = I{B^{2021}}I$$<br><br>$$ \Rightarrow A{Q^{2021}}\,{A^T} = {B^{2021}} = \left( {\matrix{
